import { ErrorStackOptions } from './error-options.js';

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function stripInternal(lines: string[], mode: ErrorStackOptions['stripInternalFrames']): string[] {
  if (mode === 'none') return lines;
  return lines.filter((line, index) => {
    if (index === 0) return true;
    const node = line.includes('node:internal');
    const superjson = /src\/(transformer|plainer|index)\.ts/.test(line);
    return !((mode === 'node' || mode === 'node_and_superjson') && node) &&
      !((mode === 'superjson' || mode === 'node_and_superjson') && superjson);
  });
}

function redact(line: string, mode: ErrorStackOptions['redactPaths']): string {
  if (mode === 'none') return line;
  if (mode === 'strip_cwd') {
    const cwd = process.cwd().replace(/\\/g, '/').replace(/\/$/, '');
    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '/?', 'g'), '');
  }
  return line.replace(/(?:file:\/\/)?(?:[A-Za-z]:)?[\\/][^\s()]+(?=:\d+(?::\d+)?|[)\s]|$)/g, path => {
    const clean = path.replace(/^file:\/\//, '');
    return clean.slice(Math.max(clean.lastIndexOf('/'), clean.lastIndexOf('\\')) + 1);
  });
}

function initialLines(stack: string, options: ErrorStackOptions): string[] {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const lines = normalized.split('\n');
  return options.trimLeadingWhitespace
    ? lines.map((line, index) => index === 0 ? line : line.replace(/^\s+/, ''))
    : lines;
}

export function processStackString(stack: string, options: ErrorStackOptions): string {
  let lines = initialLines(stack, options).map(line => redact(line, options.redactPaths));
  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
  lines = stripInternal(lines, options.stripInternalFrames);
  return lines.join('\n');
}

export function processStackFrames(stack: string, options: ErrorStackOptions): Array<{ raw: string }> {
  let lines = stripInternal(initialLines(stack, options), options.stripInternalFrames)
    .map(line => redact(line, options.redactPaths));
  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
  return lines.map(raw => ({ raw }));
}
export type ErrorStackMode = 'off' | 'string' | 'frames';
export type StripInternalFrames = 'none' | 'node' | 'superjson' | 'node_and_superjson';
export type RedactPaths = 'none' | 'basename' | 'strip_cwd';
export type IncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: StripInternalFrames;
  redactPaths: RedactPaths;
  includeCauses: IncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter?: string[];
}

const oneOf = <T extends string>(value: unknown, choices: readonly T[], fallback: T): T =>
  typeof value === 'string' && (choices as readonly string[]).includes(value)
    ? value as T
    : fallback;

export function normalizeErrorStackOptions(value: unknown): ErrorStackOptions | undefined {
  if (typeof value !== 'object' || value === null || Array.isArray(value)) return undefined;
  const raw = value as Record<string, unknown>;
  const mode = oneOf(raw.mode, ['off', 'string', 'frames'] as const, 'off');
  const maxStackLines = raw.maxStackLines;
  const maxCauseDepth = raw.maxCauseDepth;
  const invalidStackLimit = maxStackLines !== undefined &&
    (!Number.isInteger(maxStackLines) || (maxStackLines as number) <= 0);
  const invalidCauseDepth = maxCauseDepth !== undefined && !Number.isInteger(maxCauseDepth);

  return {
    mode: invalidStackLimit ? 'off' : mode,
    normalizeNewlines: raw.normalizeNewlines === true,
    trimLeadingWhitespace: raw.trimLeadingWhitespace !== false,
    maxStackLines: maxStackLines as number | undefined,
    stripInternalFrames: oneOf(raw.stripInternalFrames, ['none', 'node', 'superjson', 'node_and_superjson'] as const, 'none'),
    redactPaths: oneOf(raw.redactPaths, ['none', 'basename', 'strip_cwd'] as const, 'none'),
    includeCauses: invalidCauseDepth ? 'none' : oneOf(raw.includeCauses, ['none', 'direct', 'deep'] as const, 'none'),
    maxCauseDepth: invalidCauseDepth ? 16 : (maxCauseDepth as number | undefined) ?? 16,
    sanitizeMessage: raw.sanitizeMessage === true,
    classFilter: typeof raw.classFilter === 'string'
      ? [raw.classFilter]
      : Array.isArray(raw.classFilter)
      ? raw.classFilter.filter((item): item is string => typeof item === 'string')
      : undefined,
  };
}
